module top_module(
    input [15:0] mux_D,
    input [3:0] S,
    input VPWR,
    input VGND,
    input VPB,
    input VNB,
    output reg Z
);always @*
begin
    case (S)
        4'b0000: Z = mux_D[0];
        4'b0001: Z = mux_D[1];
        4'b0010: Z = mux_D[2];
        4'b0011: Z = mux_D[3];
        4'b0100: Z = mux_D[4];
        4'b0101: Z = mux_D[5];
        4'b0110: Z = mux_D[6];
        4'b0111: Z = mux_D[7];
        4'b1000: Z = mux_D[8];
        4'b1001: Z = mux_D[9];
        4'b1010: Z = mux_D[10];
        4'b1011: Z = mux_D[11];
        4'b1100: Z = mux_D[12];
        4'b1101: Z = mux_D[13];
        4'b1110: Z = mux_D[14];
        4'b1111: Z = mux_D[15];
        default: Z = 1'bx;
    endcase
end

endmodule
